// Classify the meeting notes into ONE DGIPR post type, using the type catalog
// the API sends in the webhook payload (builtin + custom types; each type's
// description is what routes notes to it).
const notes = ($input.first().json.meeting_notes || '').toString().trim();
if (!notes) { throw new Error('No "meeting_notes" received from the form.'); }

const types = $('DGIPR Post Form').first().json.types;
if (!Array.isArray(types) || types.length === 0) { throw new Error('No reference type catalog ("types") received from the API.'); }

const typeLines = types.map((t) => '- "' + t.slug + '": ' + t.description);
const slugs = types.map((t) => t.slug);

const system = [
  'You are an editorial classifier for DGIPR Maharashtra (Directorate General of Information & Public Relations).',
  'You read raw meeting notes and decide which ONE poster format best fits the PRIMARY message.',
  'If the notes cover several topics, pick the single most important/foreground topic.',
  'Respond with STRICT JSON only.',
  '',
  'Post types:',
].concat(typeLines).concat([
  '',
  'title: a short Marathi (Devanagari) working title for the post.',
  'reason: one short English sentence on why this type fits best.',
]).join('\n');

const body = {
  model: 'gpt-4o-mini',
  temperature: 0,
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: 'Meeting notes:\n' + notes },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'post_classification',
      strict: true,
      schema: {
        type: 'object',
        additionalProperties: false,
        properties: {
          post_type: { type: 'string', enum: slugs },
          title: { type: 'string' },
          reason: { type: 'string' },
        },
        required: ['post_type', 'title', 'reason'],
      },
    },
  },
};

return [{ json: { body, meeting_notes: notes } }];

// Resolve the post type — the API's forced pin, or the classifier result — then
// build the copy request from the catalog entry's copy_style. The catalog comes
// from the API payload, so custom types work without touching this workflow.
const form = $('DGIPR Post Form').first().json;
const types = form.types;
if (!Array.isArray(types) || types.length === 0) { throw new Error('No reference type catalog ("types") received from the API.'); }
const bySlug = {};
for (const t of types) { bySlug[t.slug] = t; }

const forced = (form.forced_type || '').toString().trim();
let post_type;
let title;
if (forced) {
  // Pinned run: this node is reached straight from IF Forced Type (no classifier call).
  if (!bySlug[forced]) { throw new Error('forced_type "' + forced + '" is not in the type catalog.'); }
  post_type = forced;
  title = bySlug[forced].label;
} else {
  const res = $input.first().json;
  const content = res && res.choices && res.choices[0] && res.choices[0].message ? res.choices[0].message.content : undefined;
  if (!content) { throw new Error('No classifier content: ' + JSON.stringify(res).slice(0, 500)); }
  let cls;
  try { cls = typeof content === 'string' ? JSON.parse(content) : content; }
  catch (e) { throw new Error('Classifier JSON parse failed: ' + e.message + ' | raw: ' + String(content).slice(0, 400)); }
  post_type = cls.post_type;
  title = cls.title;
  if (!bySlug[post_type]) {
    // Fall back to the most list-like entry the catalog offers.
    const fallback = types.find((t) => t.copy_style === 'info_bullets') || types.find((t) => t.copy_style === 'generic') || types[0];
    post_type = fallback.slug;
  }
}

const typeEntry = bySlug[post_type];
const reference_url = ((form.forced_reference_url || '').toString().trim()) || typeEntry.reference_url || '';

const notes = form.meeting_notes;

const str = { type: 'string' };
const bulletItem = {
  type: 'object', additionalProperties: false,
  properties: { text: str, emphasis: { type: 'array', items: str } },
  required: ['text', 'emphasis'],
};
const obj = (props, required) => ({ type: 'object', additionalProperties: false, properties: props, required: required });

const REG = {
  alert: {
    system: [
      'ALERT poster. Fields:',
      '- kicker: 1-2 word Marathi alert tag (e.g. सावधान, सूचना, इशारा).',
      '- headline: punchy Marathi headline, 3-6 words.',
      '- subhead: one supporting Marathi line, about 8-12 words.',
      '- bullets: EXACTLY 3 items; each text is a short Marathi action (<=10 words); emphasis = 1-2 substrings copied VERBATIM from that same text.',
      '- scene_brief: one English sentence describing only the background imagery.',
    ].join('\n'),
    schema: obj({ kicker: str, headline: str, subhead: str, bullets: { type: 'array', items: bulletItem }, scene_brief: str }, ['kicker', 'headline', 'subhead', 'bullets', 'scene_brief']),
  },
  campaign: {
    system: [
      'CAMPAIGN / DRIVE / SERVICE poster. Fields:',
      '- kicker: 1-2 word Marathi tag (e.g. मोहीम, लसीकरण, सेवा).',
      '- headline: the Marathi campaign/event name, 3-7 words.',
      '- subhead: one Marathi line on the purpose or target.',
      '- schedule.date and schedule.time: Marathi date and time strings if the notes give them, else empty strings.',
      '- audience: Marathi eligibility/audience line, else empty string.',
      '- cta: a strong Marathi call-to-action, else empty string.',
      '- stats: 2-4 items, each { value (figure as given), label (short Marathi), icon_hint (1-3 English words naming an icon) }. Use only figures present in the notes.',
      '- scene_brief: one English sentence, background/hero imagery only.',
    ].join('\n'),
    schema: obj({
      kicker: str, headline: str, subhead: str,
      schedule: obj({ date: str, time: str }, ['date', 'time']),
      audience: str, cta: str,
      stats: { type: 'array', items: obj({ value: str, label: str, icon_hint: str }, ['value', 'label', 'icon_hint']) },
      scene_brief: str,
    }, ['kicker', 'headline', 'subhead', 'schedule', 'audience', 'cta', 'stats', 'scene_brief']),
  },
  info_bullets: {
    system: [
      'INFORMATIONAL poster (headline + points). Fields:',
      '- kicker: short Marathi tag, else empty string.',
      '- headline: Marathi headline, 3-8 words.',
      '- subhead: one supporting Marathi line.',
      '- bullets: 4 to 6 items; each text a concise Marathi point; emphasis = 0-2 substrings copied VERBATIM from that text.',
      '- scene_brief: one English sentence, background imagery only.',
    ].join('\n'),
    schema: obj({ kicker: str, headline: str, subhead: str, bullets: { type: 'array', items: bulletItem }, scene_brief: str }, ['kicker', 'headline', 'subhead', 'bullets', 'scene_brief']),
  },
  quote: {
    system: [
      'QUOTE / STATEMENT poster. Fields:',
      '- topic_label: short Marathi tag (e.g. चर्चा, गुंतवणूक).',
      '- headline: Marathi subject line (what the statement is about).',
      '- quote_text: the main Marathi quote (one or two sentences).',
      '- attribution.name and attribution.title: Marathi name and designation of the speaker.',
      '- points: 2-3 supporting items, each { text (short Marathi), icon_hint (1-3 English words) }.',
      '- scene_brief: one English sentence, thematic background imagery only.',
    ].join('\n'),
    schema: obj({
      topic_label: str, headline: str, quote_text: str,
      attribution: obj({ name: str, title: str }, ['name', 'title']),
      points: { type: 'array', items: obj({ text: str, icon_hint: str }, ['text', 'icon_hint']) },
      scene_brief: str,
    }, ['topic_label', 'headline', 'quote_text', 'attribution', 'points', 'scene_brief']),
  },
  timeline: {
    system: [
      'TIMELINE / ACHIEVEMENTS poster. Fields:',
      '- headline: Marathi headline.',
      '- intro: one Marathi line introducing the sequence, else empty string.',
      '- side_label: a longer Marathi phrase used as a bold side/emphasis label, else empty string.',
      '- milestones: 3-4 items in chronological order, each { date (Marathi date/period), text (short Marathi description) }.',
      '- scene_brief: one English sentence, background imagery only.',
    ].join('\n'),
    schema: obj({
      headline: str, intro: str, side_label: str,
      milestones: { type: 'array', items: obj({ date: str, text: str }, ['date', 'text']) },
      scene_brief: str,
    }, ['headline', 'intro', 'side_label', 'milestones', 'scene_brief']),
  },
  generic: {
    system: [
      'GENERIC poster (headline + supporting points). Fields:',
      '- kicker: short Marathi tag, else empty string.',
      '- headline: Marathi headline, 3-8 words.',
      '- subhead: one supporting Marathi line.',
      '- bullets: 3 to 6 items; each text a concise Marathi point; emphasis = 0-2 substrings copied VERBATIM from that text.',
      '- scene_brief: one English sentence, background imagery only.',
    ].join('\n'),
    schema: obj({ kicker: str, headline: str, subhead: str, bullets: { type: 'array', items: bulletItem }, scene_brief: str }, ['kicker', 'headline', 'subhead', 'bullets', 'scene_brief']),
  },
};

const COMMON = [
  'You are a senior bilingual (Marathi/English) creative director for DGIPR Maharashtra. You write copy for an OFFICIAL government poster. Respond with STRICT JSON only, no commentary.',
  'All on-poster copy MUST be natural Marathi in the Devanagari script. The scene_brief is ENGLISH only and describes ONLY background imagery (never any text, words, letters, numbers or logos).',
  'Base everything strictly on the supplied notes; do not invent facts. If a field is not supported by the notes, use an empty string (and keep arrays to only what the notes support).',
].join('\n');

// Custom types render with the generic layout; unknown copy_styles fall back too.
const copy_style = REG[typeEntry.copy_style] ? typeEntry.copy_style : 'generic';
const reg = REG[copy_style];
const system = COMMON + '\n\n' + reg.system;

const body = {
  model: 'gpt-4o-mini',
  temperature: 0.6,
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: 'Notes for the ' + post_type + ' poster:\n' + notes },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: { name: copy_style + '_copy', strict: true, schema: reg.schema },
  },
};

return [{ json: { body, post_type, copy_style, reference_url, title, meeting_notes: notes } }];

// Parse the copy JSON and assemble the image prompt for the resolved type + design mode.
const res = $input.first().json;
const content = res && res.choices && res.choices[0] && res.choices[0].message ? res.choices[0].message.content : undefined;
if (!content) { throw new Error('No copy content: ' + JSON.stringify(res).slice(0, 500)); }

let copy;
try { copy = typeof content === 'string' ? JSON.parse(content) : content; }
catch (e) { throw new Error('Copy JSON parse failed: ' + e.message + ' | raw: ' + String(content).slice(0, 400)); }

const post_type = $('Build Copy Request').first().json.post_type;
const copy_style = $('Build Copy Request').first().json.copy_style;
const title = $('Build Copy Request').first().json.title;

const dmRaw = ($('DGIPR Post Form').first().json.design_mode || '').toString().toLowerCase();
const design_mode = dmRaw.indexOf('fresh') !== -1 ? 'fresh' : (dmRaw.indexOf('adaptive') !== -1 ? 'adaptive' : 'onbrand');

// The master to edit is the immutable library URL the API sent in the catalog
// (forced_reference_url wins on pinned runs — resolved in Build Copy Request).
const masterFile = ($('Build Copy Request').first().json.reference_url || '').toString().trim();
if (design_mode !== 'fresh' && !masterFile) { throw new Error('No reference_url for type "' + post_type + '" — the API must send the enabled-image catalog.'); }

const fmtBullets = (arr) => (arr || []).map((b, i) => {
  const e = (b.emphasis || []).filter(Boolean);
  return '  ' + (i + 1) + '. ' + b.text + (e.length ? '  [emphasise: ' + e.join(' | ') + ']' : '');
}).join('\n');

// Dispatches on copy_style (not the type slug), so custom types render with the
// generic (headline + points) layout.
function buildChange(t, c) {
  let lines;
  if (t === 'alert') {
    lines = [
      'KICKER (small alert tag near the top): ' + c.kicker,
      'HEADLINE (largest text block): ' + c.headline,
      'SUBHEAD (line under the headline): ' + c.subhead,
      'BULLET POINTS (exactly 3, in the body list zone):',
      fmtBullets(c.bullets),
    ];
  } else if (t === 'campaign') {
    const sch = c.schedule || {};
    lines = [
      'KICKER (small tag near the top): ' + c.kicker,
      'HEADLINE (largest block, the campaign name): ' + c.headline,
      'SUBHEAD: ' + c.subhead,
      'DATE: ' + (sch.date || ''),
      'TIME: ' + (sch.time || ''),
      'AUDIENCE / ELIGIBILITY: ' + (c.audience || ''),
      'CALL TO ACTION (make it prominent): ' + (c.cta || ''),
      'STAT CALLOUTS (each as icon + figure + label):',
      (c.stats || []).map((s, i) => '  ' + (i + 1) + '. ' + s.value + ' — ' + s.label + '  [icon: ' + s.icon_hint + ']').join('\n'),
    ];
  } else if (t === 'quote') {
    const at = c.attribution || {};
    lines = [
      'TOPIC LABEL (small tag near the top): ' + c.topic_label,
      'HEADLINE (subject line): ' + c.headline,
      'QUOTE (main text, inside large quotation marks): ' + c.quote_text,
      'ATTRIBUTION (name then designation): ' + (at.name || '') + ', ' + (at.title || ''),
      'SUPPORTING POINTS (each as icon + text):',
      (c.points || []).map((p, i) => '  ' + (i + 1) + '. ' + p.text + '  [icon: ' + p.icon_hint + ']').join('\n'),
    ];
  } else if (t === 'timeline') {
    lines = [
      'SIDE LABEL (bold side/left emphasis text): ' + (c.side_label || ''),
      'HEADLINE (top): ' + c.headline,
      'INTRO: ' + (c.intro || ''),
      'TIMELINE MILESTONES (dated, top to bottom):',
      (c.milestones || []).map((m, i) => '  ' + (i + 1) + '. [' + m.date + '] ' + m.text).join('\n'),
    ];
  } else {
    // info_bullets and generic share the headline + points layout.
    lines = [
      'KICKER (small tag): ' + c.kicker,
      'HEADLINE (largest block): ' + c.headline,
      'SUBHEAD: ' + c.subhead,
      'BULLET POINTS (in the body list zone):',
      fmtBullets(c.bullets),
    ];
  }
  return lines.join('\n');
}

const change = buildChange(copy_style, copy);

const BRAND = "The footer band reads 'माहिती व जनसंपर्क महासंचालनालय, महाराष्ट्र शासन' above a social-handle strip (www.mahasamvad.in, @MahaDGIPR, @MAHARASHTRADGIPR). The top-right carries the Government of Maharashtra emblem with 'महाराष्ट्र शासन'.";

let prompt;
if (design_mode === 'fresh') {
  prompt = [
    'Design a single, complete 4:5 portrait OFFICIAL DGIPR Maharashtra government poster from scratch.',
    'Government public-information aesthetic: bold, high-contrast, highly legible Devanagari (Marathi) typography, clean and trustworthy layout, strong colour blocks suited to the topic.',
    'Choose a layout appropriate to a "' + copy_style + '" poster. ' + BRAND,
    'Render ALL Marathi text crisply and correctly in Devanagari, spelled EXACTLY as given. Do not add English body text beyond the fixed footer handles. One poster, no outer border.',
    '',
    'CONTENT TO TYPESET:',
    change,
    '',
    'BACKGROUND IMAGERY (must never cover the text): ' + copy.scene_brief,
  ].join('\n');
} else {
  const layoutRule = design_mode === 'adaptive'
    ? "You MAY re-arrange and resize the template's text zones to best fit the content, but keep its brand colours, header emblem and footer band."
    : "KEEP the master template's overall layout, proportions, brand colour bands, header and footer zones and safe margins EXACTLY as in the provided image.";
  const LOCKED = [
    'You are editing a master template for an OFFICIAL DGIPR Maharashtra government poster (type: ' + copy_style + ').',
    layoutRule,
    'The master template you are editing still carries PLACEHOLDER content from a previous poster: sample Marathi text in every text zone (headline, tag, bullets, figures, dates) and a sample photo/illustration in the image zone. NONE of that content relates to this poster. ERASE every piece of existing sample text and ERASE the existing photo/illustration completely before adding the new content — no word, number, person, or pictorial element from the placeholder may survive into the output. Only the brand frame stays: colour bands, header emblem, footer band, social-handle strip.',
    'Single 4:5 portrait poster. Typography: bold, high-contrast, highly legible Devanagari (Marathi). Government public-notice aesthetic: clean, serious, trustworthy.',
    'Render ALL Marathi text crisply and correctly in Devanagari, spelled exactly as below.',
  ].join(' ');
  prompt = [
    LOCKED,
    '',
    "REPLACE the editable content of the poster with the following, fitting the master's existing text zones:",
    '',
    change,
    '',
    "BACKGROUND IMAGERY — first erase the master's existing photo/illustration, then paint a NEW scene in the image zone (must never cover the text): " + copy.scene_brief,
    '',
    'Do not add any English text beyond the fixed footer handles. Do not add extra logos. Keep one single poster within the canvas, no outer borders.',
  ].join('\n');
}

return [{ json: { prompt, copy, post_type, copy_style, title, design_mode, masterFile } }];

// Decode the base64 PNG returned by whichever image step ran into an n8n binary item.
const res = $input.first().json;
const b64 = res && res.data && res.data[0] ? res.data[0].b64_json : undefined;
if (!b64) { throw new Error('No image b64_json returned: ' + JSON.stringify(res).slice(0, 500)); }

const post_type = $('Build Image Prompt').first().json.post_type;
const title = $('Build Image Prompt').first().json.title;
const fileName = post_type + '-' + $now.toFormat('yyyyLLdd-HHmmss') + '.png';

return [{
  json: { fileName, post_type, title, b64 },
  binary: { data: { data: b64, mimeType: 'image/png', fileName: fileName, fileExtension: 'png' } },
}];

// Build the X (Twitter) caption request from the structured copy + the original notes.
const copy = $('Build Image Prompt').first().json.copy;
const post_type = $('Build Image Prompt').first().json.post_type;
const notes = $('DGIPR Post Form').first().json.meeting_notes;

const styleGuide = [
  'House style for DGIPR Maharashtra posts on X (formerly Twitter):',
  '- Lead in Marathi (Devanagari). Keep it crisp, factual and public-spirited; an English gloss line is optional.',
  '- 1-3 short lines, then a blank line, then the hashtags.',
  '- Always mention @MahaDGIPR. Include 2-4 relevant hashtags (mix of Marathi and English) plus topic tags.',
  '- At most 1-2 tasteful emojis. No clickbait. Stay on-message with the notes.',
].join('\n');

const system = 'You are the social media editor for DGIPR Maharashtra. Write ONE ready-to-post X caption for the poster described. Respond with STRICT JSON only: { "caption": string }.\n\n' + styleGuide;

const user = 'Post type: ' + post_type + '\n\nMeeting notes:\n' + notes + '\n\nPoster copy (keep the caption consistent with this):\n' + JSON.stringify(copy);

const body = {
  model: 'gpt-4o-mini',
  temperature: 0.7,
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: user },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: { name: 'x_caption', strict: true, schema: { type: 'object', additionalProperties: false, properties: { caption: { type: 'string' } }, required: ['caption'] } },
  },
};

return [{ json: { body } }];

// Turn the caption text into a UTF-8 .txt binary, named to match the poster PNG.
const res = $input.first().json;
const content = res && res.choices && res.choices[0] && res.choices[0].message ? res.choices[0].message.content : undefined;
if (!content) { throw new Error('No caption content: ' + JSON.stringify(res).slice(0, 400)); }

let parsed;
try { parsed = typeof content === 'string' ? JSON.parse(content) : content; }
catch (e) { parsed = { caption: String(content) }; }

const caption = (parsed.caption || '').toString();
const pngName = $('Decode Image').first().json.fileName;
const fileName = pngName.replace('.png', '.txt');

return [{
  json: { caption, fileName },
  binary: { data: { data: Buffer.from(caption, 'utf8').toString('base64'), mimeType: 'text/plain', fileName: fileName, fileExtension: 'txt' } },
}];
